const webhookItem = $('Webhook').first().json;
const queryText = webhookItem.body?.query ?? webhookItem.query;

if (!queryText || typeof queryText !== 'string') {
  throw new Error('Request body must include a string field named query.');
}

const embeddings = $json.embeddings;
if (!Array.isArray(embeddings) || !Array.isArray(embeddings[0])) {
  throw new Error('Ollama response did not contain embeddings[0].');
}

const vector = embeddings[0];
const vectorLiteral = `[${vector.join(',')}]`;

return [{
  json: {
    query: queryText,
    vector_literal: vectorLiteral
  }
}];

const query = $('Prepare Vector').first().json.query;
const items = $input.all();

const matches = items.map((item) => {
  const row = item.json || {};
  return {
    id: row.id,
    title: row.title,
    category: row.category,
    source: row.source,
    content: row.content,
    similarity: typeof row.similarity === 'number'
      ? Number(row.similarity.toFixed(6))
      : row.similarity
  };
});

const contextText = matches.length
  ? matches.map((match, index) => {
      return [
        `Memory ${index + 1}`,
        `Title: ${match.title ?? ''}`,
        `Category: ${match.category ?? ''}`,
        `Source: ${match.source ?? ''}`,
        `Content: ${match.content ?? ''}`
      ].join('\n');
    }).join('\n\n')
  : 'No relevant memories found.';

return [{
  json: {
    query,
    match_count: matches.length,
    matches,
    context_text: contextText
  }
}];
